import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreRuntimeState', () {
    test('allows scheduling only while auto-explore owns motion', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).canScheduleZoomLeg,
        isTrue,
      );

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
      ]) {
        expect(state.canScheduleZoomLeg, isFalse);
        expect(state.shouldInterruptAnimation, isTrue);
      }
    });

    test('keeps user-correction pause as an explicit motion blocker', () {
      final yieldedWithoutInteraction = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: true,
      );

      expect(yieldedWithoutInteraction.canScheduleZoomLeg, isFalse);
      expect(yieldedWithoutInteraction.shouldInterruptAnimation, isTrue);
    });

    test('gates one-shot corrections while continuous gestures own motion', () {
      final idleAutoExplore = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: false,
      );
      final continuousGesture = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: true,
        pausedByUserCorrection: true,
      );

      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          idleAutoExplore,
        ),
        isTrue,
      );
      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          continuousGesture,
        ),
        isFalse,
      );
    });

    test('characterizes user-correction pause as armed auto-explore only', () {
      expect(
        () => AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
      expect(
        () => AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
    });
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreService', () {
    test('ignores one-shot corrections during continuous user interaction',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);

      controller.updateZoom(2.0);
      service.onUserCorrection();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.onUserInteractionEnd();

      expect(service.pausedByUserCorrection, isFalse);
    });

    test('resume replans from a zoom changed while paused', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.pause();

      controller.updateZoom(10.0);
      service.resume();

      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 1200.0);
    });
  });
}

